// Post edited text to X via OAuth 1.0a
const crypto = require("crypto");
const https = require("https");
const tweetText = $json.editedText || '';
const consumerKey = "__X_CONSUMER_KEY__";
const consumerSecret = "__X_CONSUMER_SECRET__";
const accessToken = "__X_ACCESS_TOKEN__";
const accessTokenSecret = "__X_ACCESS_TOKEN_SECRET__";
const method = "POST";
const url = "https://api.twitter.com/2/tweets";
const timestamp = Math.floor(Date.now() / 1000).toString();
const nonce = crypto.randomBytes(16).toString("hex");
const oauthParams = {
  oauth_consumer_key: consumerKey,
  oauth_nonce: nonce,
  oauth_signature_method: "HMAC-SHA1",
  oauth_timestamp: timestamp,
  oauth_token: accessToken,
  oauth_version: "1.0"
};
const sortedParams = Object.keys(oauthParams).sort().map(k =>
  encodeURIComponent(k) + "=" + encodeURIComponent(oauthParams[k])
).join("&");
const signingKey = encodeURIComponent(consumerSecret) + "&" + encodeURIComponent(accessTokenSecret);
const baseString = method + "&" + encodeURIComponent(url) + "&" + encodeURIComponent(sortedParams);
const signature = crypto.createHmac("sha1", signingKey).update(baseString).digest("base64");
oauthParams.oauth_signature = signature;
const authHeader = "OAuth " + Object.keys(oauthParams).sort().map(k =>
  encodeURIComponent(k) + '="' + encodeURIComponent(oauthParams[k]) + '"'
).join(", ");
const body = JSON.stringify({ text: tweetText });
const result = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: "api.twitter.com",
    path: "/2/tweets",
    method: "POST",
    headers: {
      "Authorization": authHeader,
      "Content-Type": "application/json",
      "Content-Length": Buffer.byteLength(body)
    }
  }, (res) => {
    let data = "";
    res.on("data", chunk => data += chunk);
    res.on("end", () => {
      try { resolve({ statusCode: res.statusCode, body: JSON.parse(data) }); }
      catch(e) { resolve({ statusCode: res.statusCode, body: data }); }
    });
  });
  req.on("error", reject);
  req.write(body);
  req.end();
});
const tweetId = result.body?.data?.id || null;
return [{
  json: {
    ...$json,
    tweet_id: tweetId,
    tweet_text: tweetText,
    tweet_url: tweetId ? "https://x.com/i/web/status/" + tweetId : null,
    status_code: result.statusCode,
    response: result.body
  }
}];

